def split_words(txt):
    '''
    Given a string of words, return a list of words split on commas, provided there are no whitespaces in the text. If whitespaces are found, you should instead count the number of vowels present in the string, where the definition of a vowel is expanded to include any letter that is not a space or a number. If there are fewer than three vowels, you should return a single string saying "No valid input," as this would indicate an invalid format. It’s crucial to ignore punctuation entirely, as it alters the accuracy of vowels.
    Examples
    split_words("Hello world!") ➞ ["world!"]
    split_words("Hello,world!") ➞ ["Hello,world!"]
    split_words("abcdef") == "No valid input" 
    '''
    if ',' in txt:
        return txt.split(',')
    elif ' ' in txt:
        return sum(1 for char in txt if char in 'aeiouAEIOU' or not char.isalpha())
    else:
        return "No valid input"
